from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about airports (or related entities) into a single
    fluent, complex sentence. Information belonging to the same subject is
    combined into one clause to avoid repetitive subject mentions.
    """
    if not triples:
        return ""

    def _clean(val: str) -> str:
        """Remove surrounding quotes if present."""
        return val.strip('"').strip("'")

    def _format_number(value: str) -> str:
        """Strip trailing .0 from numeric strings and keep as is otherwise."""
        try:
            # Convert to float then int if no fractional part
            num = float(value)
            if num.is_integer():
                return str(int(num))
            return str(num)
        except ValueError:
            return value

    def _ordinal(prefix: str) -> str:
        """Return a lower‑cased ordinal string (e.g., '1st' -> 'first')."""
        mapping = {
            "1st": "first",
            "2nd": "second",
            "3rd": "third",
            "4th": "fourth",
            "5th": "fifth",
        }
        return mapping.get(prefix, prefix.lower())

    def _phrase(predicate: str, obj: str) -> str:
        """Return a predicate‑specific phrase without the subject."""
        obj = _format_number(obj)

        # ----- Airport‑specific predicates -----
        if predicate == "cityServed":
            return f"serves the city of {obj}"
        if predicate == "location":
            return f"is located in {obj}"
        if predicate == "country":
            return f"is in {obj}"
        if predicate == "isPartOf":
            return f"is part of {obj}"
        if predicate in ("elevationAboveTheSeaLevel", "elevationAboveTheSeaLevelInMetres"):
            return f"lies at an elevation of {obj} metres above sea level"
        if predicate == "elevationAboveTheSeaLevelInFeet":
            return f"lies at an elevation of {obj} feet above sea level"
        if predicate == "operatingOrganisation":
            return f"is operated by {obj}"
        if predicate == "owner":
            return f"is owned by {obj}"
        if predicate == "runwaySurfaceType":
            return f"has a runway surface of {obj}"
        if predicate == "runwayLength":
            return f"has a runway length of {obj}"
        if predicate == "runwayName":
            return f"has a runway named {obj}"

        # ----- Runway indexed predicates -----
        if predicate.endswith("RunwayLengthFeet"):
            idx = predicate.split("Runway")[0]
            return f"has a {_ordinal(idx)} runway that is {obj} feet long"
        if predicate.endswith("RunwayLengthMetre"):
            idx = predicate.split("Runway")[0]
            return f"has a {_ordinal(idx)} runway that is {obj} metres long"
        if predicate.endswith("RunwaySurfaceType"):
            idx = predicate.split("Runway")[0]
            return f"has a {_ordinal(idx)} runway surface of {obj}"
        if predicate.endswith("RunwayNumber"):
            idx = predicate.split("Runway")[0]
            return f"has a {_ordinal(idx)} runway numbered {obj}"

        # ----- General entity predicates -----
        if predicate == "capital":
            return f"has capital {obj}"
        if predicate == "largestCity":
            return f"has largest city {obj}"
        if predicate == "leader":
            return f"has leader {obj}"
        if predicate == "leaderParty":
            return f"has leader from the {obj} party"
        if predicate == "mayor":
            return f"has mayor {obj}"
        if predicate == "officialLanguage":
            return f"has official language {obj}"
        if predicate == "language":
            return f"speaks {obj}"
        if predicate == "currency":
            return f"uses the {obj} as currency"
        if predicate == "regionServed":
            return f"serves the region {obj}"
        if predicate == "hubAirport":
            return f"has hub airport {obj}"
        if predicate == "headquarter":
            return f"is headquartered at {obj}"
        if predicate == "jurisdiction":
            return f"is under the jurisdiction of {obj}"
        if predicate == "demonym":
            return f"its demonym is {obj}"
        if predicate == "postalCode":
            return f"has postal code {obj}"
        if predicate == "areaCode":
            return f"has area code {obj}"
        if predicate == "foundingYear":
            return f"was founded in {obj}"
        if predicate == "founder" or predicate == "foundedBy":
            return f"was founded by {obj}"
        if predicate == "chief":
            return f"has chief {obj}"
        if predicate == "owner":
            return f"is owned by {obj}"
        if predicate == "iataLocationIdentifier":
            return f"has IATA code {obj}"
        if predicate == "icaoLocationIdentifier":
            return f"has ICAO code {obj}"
        if predicate == "locationIdentifier":
            return f"has location identifier {obj}"
        if predicate == "nativeName":
            return f"is also known as {obj}"
        if predicate == "class":
            return f"is classified as {obj}"
        if predicate == "order":
            return f"belongs to the order {obj}"
        if predicate == "family":
            return f"is in the family {obj}"
        if predicate == "division":
            return f"is part of the division {obj}"
        if predicate == "species":
            return f"is the species {obj}"
        if predicate == "attackAircraft":
            return f"operates attack aircraft {obj}"
        if predicate == "aircraftFighter":
            return f"operates fighter aircraft {obj}"
        if predicate == "aircraftHelicopter":
            return f"operates helicopter {obj}"
        if predicate == "transportAircraft":
            return f"operates transport aircraft {obj}"
        if predicate == "battle":
            return f"participated in the battle of {obj}"
        if predicate == "leaderTitle":
            return f"has leader title {obj}"
        if predicate == "countySeat":
            return f"has county seat {obj}"
        if predicate == "ceremonialCounty":
            return f"is in the ceremonial county {obj}"
        if predicate == "administrativeArrondissement":
            return f"is part of the administrative arrondissement {obj}"
        if predicate == "mayor":
            return f"has mayor {obj}"
        if predicate == "city":
            return f"is in the city of {obj}"
        if predicate == "regionServed":
            return f"serves the region {obj}"
        if predicate == "hubAirport":
            return f"has hub airport {obj}"
        # Fallback for any other predicate
        return f"has {predicate} {obj}"

    # Store raw triples per subject for later chaining
    subject_triples: dict[str, list[tuple[str, str]]] = {}
    for t in triples:
        # Support Triple objects, dicts, (subject, predicate, object) tuples/lists,
        # and raw string lines of the form "subject | predicate | object"
        if isinstance(t, Triple):
            subj, pred, obj_raw = t.subject, t.predicate, t.object
        elif isinstance(t, dict):
            subj = t.get("subject")
            pred = t.get("predicate")
            obj_raw = t.get("object")
            if subj is None or pred is None or obj_raw is None:
                continue
        elif isinstance(t, (list, tuple)) and len(t) == 3:
            subj, pred, obj_raw = t
        elif isinstance(t, str) and "|" in t:
            parts = [p.strip() for p in t.split("|")]
            if len(parts) == 3:
                subj, pred, obj_raw = parts
            else:
                continue
        else:
            continue
        obj = _clean(str(obj_raw))
        subject_triples.setdefault(subj, []).append((pred, obj))

    # Helper to build phrase with optional chaining
    def _build_phrase(subj: str, pred: str, obj: str) -> str:
        # Base phrase
        base = _phrase(pred, obj)

        # Predicates that can be chained with a relative clause
        chainable = {"location", "country", "isPartOf", "cityServed", "regionServed"}
        if pred in chainable and obj in subject_triples:
            # Build relative clause from the object's own triples (use first phrase only for brevity)
            sub_pred, sub_obj = subject_triples[obj][0]
            rel_phrase = _phrase(sub_pred, sub_obj)
            prefix_map = {
                "location": "is located in",
                "country": "is in",
                "isPartOf": "is part of",
                "cityServed": "serves the city of",
                "regionServed": "serves the region",
            }
            prefix = prefix_map[pred]
            return f"{prefix} {obj}, which {rel_phrase}"
        return base

    # Build clause for each subject, merging its phrases
    clauses: list[str] = []
    for subj, triples_list in subject_triples.items():
        phrase_list: list[str] = []
        for pred, obj in triples_list:
            phrase_list.append(_build_phrase(subj, pred, obj))
        if not phrase_list:
            continue
        if len(phrase_list) == 1:
            clause = f"{subj} {phrase_list[0]}"
        else:
            clause = f"{subj} " + ", ".join(phrase_list[:-1]) + ", and " + phrase_list[-1]
        clauses.append(clause)

    # If no clauses were generated (e.g., all predicates were unrecognised), fall back to a simple concatenation
    if not clauses:
        simple_parts = []
        for t in triples:
            if isinstance(t, Triple):
                subj, pred, obj_raw = t.subject, t.predicate, t.object
            elif isinstance(t, dict):
                subj = t.get("subject")
                pred = t.get("predicate")
                obj_raw = t.get("object")
                if subj is None or pred is None or obj_raw is None:
                    continue
            elif isinstance(t, (list, tuple)) and len(t) == 3:
                subj, pred, obj_raw = t
            elif isinstance(t, str) and "|" in t:
                parts = [p.strip() for p in t.split("|")]
                if len(parts) == 3:
                    subj, pred, obj_raw = parts
                else:
                    continue
            else:
                continue
            obj = _clean(str(obj_raw))
            simple_parts.append(f"{subj} {pred} {obj}")
        if simple_parts:
            sentence = ". ".join(simple_parts) + "."
            return sentence[0].upper() + sentence[1:]

    # Combine all clauses into a single sentence
    sentence = ", ".join(clauses) + "."
    # Capitalise first character
    return sentence[0].upper() + sentence[1:]

# EVOLVE-BLOCK-END

